UMaterialInstanceDynamic* AMarketDistrict::CreateMaterial(const FLinearColor& BaseColor, float Roughness, float Metallic)
{
    UMaterial* BaseMaterial = LoadObject<UMaterial>(nullptr, TEXT("/Game/HoloScript/Materials/M_Standard"));
    if (!BaseMaterial) return nullptr;

    UMaterialInstanceDynamic* DynMat = UMaterialInstanceDynamic::Create(BaseMaterial, this);
    DynMat->SetVectorParameterValue(TEXT("BaseColor"), BaseColor);
    DynMat->SetScalarParameterValue(TEXT("Roughness"), Roughness);
    DynMat->SetScalarParameterValue(TEXT("Metallic"), Metallic);

    return DynMat;
}

UMaterialInstanceDynamic* AMarketDistrict::CreateEmissiveMaterial(const FLinearColor& BaseColor, const FLinearColor& EmissiveColor, float EmissiveIntensity, float Opacity)
{
    UMaterial* BaseMaterial = LoadObject<UMaterial>(nullptr, TEXT("/Game/HoloScript/Materials/M_Emissive"));
    if (!BaseMaterial) return nullptr;

    UMaterialInstanceDynamic* DynMat = UMaterialInstanceDynamic::Create(BaseMaterial, this);
    DynMat->SetVectorParameterValue(TEXT("BaseColor"), BaseColor);
    DynMat->SetVectorParameterValue(TEXT("EmissiveColor"), EmissiveColor * EmissiveIntensity);
    DynMat->SetScalarParameterValue(TEXT("Opacity"), Opacity);

    return DynMat;
}

void AMarketDistrict::ApplyMaterial(AActor* Actor, UMaterialInstanceDynamic* Material)
{
    if (!Actor || !Material) return;

    // Apply material to all mesh components
    TArray<UStaticMeshComponent*> MeshComponents;
    Actor->GetComponents<UStaticMeshComponent>(MeshComponents);

    for (UStaticMeshComponent* Mesh : MeshComponents)
    {
        Mesh->SetMaterial(0, Material);
    }
}

