void AMarketDistrict::CreateAmbientSound(const FString& Name, const FString& SoundCueName, bool bLoop, float VolumeMultiplier, bool bSpatialized, const FVector& Location)
{
    FActorSpawnParameters SpawnParams;
    SpawnParams.Owner = this;

    AAmbientSound* Sound = GetWorld()->SpawnActor<AAmbientSound>(Location, FRotator::ZeroRotator, SpawnParams);
    if (Sound && Sound->GetAudioComponent())
    {
        USoundCue* SoundCue = LoadObject<USoundCue>(nullptr, *FString::Printf(TEXT("/Game/HoloScript/Audio/%s"), *SoundCueName));
        if (SoundCue)
        {
            Sound->GetAudioComponent()->SetSound(SoundCue);
            Sound->GetAudioComponent()->bAutoActivate = true;
            Sound->GetAudioComponent()->SetVolumeMultiplier(VolumeMultiplier);

            if (bSpatialized)
            {
                Sound->GetAudioComponent()->AttenuationSettings->AttenuationShape = EAttenuationShape::Sphere;
                Sound->GetAudioComponent()->AttenuationSettings->FalloffDistance = 2000.0f; // 20m
            }
        }

        AmbientSounds.Add(Sound);
    }
}

FLinearColor AMarketDistrict::HexToColor(const FString& Hex)
{
    FString CleanHex = Hex.Replace(TEXT("#"), TEXT(""));

    if (CleanHex.Len() != 6)
        return FLinearColor::White;

    int32 R = FParse::HexNumber(*CleanHex.Mid(0, 2));
    int32 G = FParse::HexNumber(*CleanHex.Mid(2, 2));
    int32 B = FParse::HexNumber(*CleanHex.Mid(4, 2));

    return FLinearColor(R / 255.0f, G / 255.0f, B / 255.0f);
}
